UPDATE coupon
name = #{name}, description = #{description}, images = #{images}, price = #{price}, buy_amount = #{buyAmount}, send_amount = #{sendAmount}, stock = #{stock}, status = #{status},
WHERE id = #{id}

UPDATE coupon
SET status = #{status}
WHERE id = #{id}

UPDATE coupon
SET stock = stock - #{quantity}
WHERE id = #{id} AND stock >= #{quantity}

UPDATE coupon
SET stock = stock + #{quantity}
WHERE id = #{id}
